code.C:
#include <stdio.h>
#include <string.h>
int main() {
    int n;
    char str[101];
    scanf("%d", &n);
    scanf("%s", str);
    int h = 0, t = 0;
    for (int i = 0; i < n; i++) {
        if (str[i] == 'H') h++;
        else t++;
    }
    printf("%d\n", (h > t) ? h : t);
    return 0;
}

