code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        String str = scanner.next();
        int h = 0, t = 0;
        for (int i = 0; i < n; i++) {
            if (str.charAt(i) == 'H') h++;
            else t++;
        }
        System.out.println(Math.max(h, t));
    }
}

code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let str;
readline.on('line', line => {
    if (i == 0) {
        n = parseInt(line);
        i++;
    } else {
        str = line;
        let h = 0, t = 0;
        for (let j = 0; j < n; j++) {
            if (str[j] == 'H') h++;
            else t++;
        }
        console.log(Math.max(h, t));
        readline.close();
    }
});

